const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(input: any): unknown {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  const basePremium = items.reduce(
    (sum: number, item: any) => sum + BASE_PREMIUM_BY_TYPE[item.type],
    0,
  );
  const premium = basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
  return { results: [{ premium }] };
}
